{
  "children": [
    {
      "name": "ValidateAndExecuteSend",
      "purpose": "Validate user membership in the target channel, store the message, update user's last_seen, and notify other channel members.",
      "behavior": "Check if user_id is in channel's members list; if not, return error. Otherwise, generate a new message_id, store message in messages store, update user's last_seen in users store, and return success with notification data.",
      "boundary": {
        "in_scope": [
          "membership validation",
          "message storage",
          "last_seen update",
          "notification preparation"
        ],
        "out_of_scope": [
          "actual notification sending",
          "history retrieval",
          "channel creation",
          "join operations"
        ]
      },
      "preconditions": [
        "command is 'send'",
        "message_data contains content, channel_id, user_id"
      ],
      "postconditions": [
        "Message stored in messages store",
        "User's last_seen updated"
      ],
      "guarantees": [
        "Only stores message if user is member",
        "Returns error if not member"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "command",
          "type": "str",
          "description": "Must be 'send'",
          "source": "parent input"
        },
        {
          "name": "message_data",
          "type": "dict",
          "description": "Contains content, channel_id, user_id",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "message_result",
          "type": "dict",
          "description": "Success status, data (message_id), message",
          "consumer": "parent"
        }
      ],
      "signature": "def ValidateAndExecuteSend(command: str, message_data: dict) -> dict"
    },
    {
      "name": "RetrieveHistory",
      "purpose": "Retrieve the last 100 messages from a channel, sorted by timestamp descending.",
      "behavior": "Query messages store for all messages with given channel_id, sort by timestamp descending, limit to 100, and return the list.",
      "boundary": {
        "in_scope": [
          "message retrieval",
          "sorting",
          "limiting"
        ],
        "out_of_scope": [
          "message storage",
          "membership checks",
          "channel creation",
          "join"
        ]
      },
      "preconditions": [
        "command is 'history'",
        "message_data contains channel_id"
      ],
      "postconditions": [
        "Messages retrieved from store"
      ],
      "guarantees": [
        "Returns at most 100 messages",
        "Sorted descending by timestamp"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "command",
          "type": "str",
          "description": "Must be 'history'",
          "source": "parent input"
        },
        {
          "name": "message_data",
          "type": "dict",
          "description": "Contains channel_id",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "message_result",
          "type": "dict",
          "description": "Success status, data (list of messages), message",
          "consumer": "parent"
        }
      ],
      "signature": "def RetrieveHistory(command: str, message_data: dict) -> dict"
    },
    {
      "name": "CreateChannel",
      "purpose": "Create a new channel with a unique name, set the caller as creator and first member.",
      "behavior": "Check if channel name already exists in channels store; if so, return error. Otherwise, generate new channel_id, store channel with name, members list containing user_id, and created_by as user_id. Return success.",
      "boundary": {
        "in_scope": [
          "name uniqueness check",
          "channel creation",
          "member initialization"
        ],
        "out_of_scope": [
          "message storage",
          "history",
          "send",
          "join"
        ]
      },
      "preconditions": [
        "command is 'create_channel'",
        "message_data contains channel_name, user_id"
      ],
      "postconditions": [
        "New channel stored in channels store",
        "User is first member"
      ],
      "guarantees": [
        "Channel name is unique",
        "Returns error if name exists"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "command",
          "type": "str",
          "description": "Must be 'create_channel'",
          "source": "parent input"
        },
        {
          "name": "message_data",
          "type": "dict",
          "description": "Contains channel_name, user_id",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "message_result",
          "type": "dict",
          "description": "Success status, data (channel_id), message",
          "consumer": "parent"
        }
      ],
      "signature": "def CreateChannel(command: str, message_data: dict) -> dict"
    },
    {
      "name": "JoinChannel",
      "purpose": "Add the user to a channel's member list if not already a member.",
      "behavior": "Check if user_id is already in channel's members list; if so, return error. Otherwise, add user_id to members list in channels store and return success.",
      "boundary": {
        "in_scope": [
          "membership check",
          "member addition"
        ],
        "out_of_scope": [
          "message storage",
          "history",
          "send",
          "channel creation"
        ]
      },
      "preconditions": [
        "command is 'join'",
        "message_data contains channel_id, user_id"
      ],
      "postconditions": [
        "User added to channel's members list"
      ],
      "guarantees": [
        "Does not add duplicate member",
        "Returns error if already member"
      ],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "command",
          "type": "str",
          "description": "Must be 'join'",
          "source": "parent input"
        },
        {
          "name": "message_data",
          "type": "dict",
          "description": "Contains channel_id, user_id",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "message_result",
          "type": "dict",
          "description": "Success status, data (channel_id), message",
          "consumer": "parent"
        }
      ],
      "signature": "def JoinChannel(command: str, message_data: dict) -> dict"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {
      "command": [
        "ValidateAndExecuteSend",
        "RetrieveHistory",
        "CreateChannel",
        "JoinChannel"
      ],
      "message_data": [
        "ValidateAndExecuteSend",
        "RetrieveHistory",
        "CreateChannel",
        "JoinChannel"
      ]
    },
    "parent_outputs_produced_by": {
      "message_result": [
        "ValidateAndExecuteSend",
        "RetrieveHistory",
        "CreateChannel",
        "JoinChannel"
      ]
    }
  },
  "dataflow_edges": [
    {
      "from_node": "parent",
      "from_output": "command",
      "to_node": "ValidateAndExecuteSend",
      "to_input": "command",
      "note": "route send command"
    },
    {
      "from_node": "parent",
      "from_output": "message_data",
      "to_node": "ValidateAndExecuteSend",
      "to_input": "message_data",
      "note": "route send message data"
    },
    {
      "from_node": "parent",
      "from_output": "command",
      "to_node": "RetrieveHistory",
      "to_input": "command",
      "note": "route history command"
    },
    {
      "from_node": "parent",
      "from_output": "message_data",
      "to_node": "RetrieveHistory",
      "to_input": "message_data",
      "note": "route history message data"
    },
    {
      "from_node": "parent",
      "from_output": "command",
      "to_node": "CreateChannel",
      "to_input": "command",
      "note": "route create_channel command"
    },
    {
      "from_node": "parent",
      "from_output": "message_data",
      "to_node": "CreateChannel",
      "to_input": "message_data",
      "note": "route create_channel message data"
    },
    {
      "from_node": "parent",
      "from_output": "command",
      "to_node": "JoinChannel",
      "to_input": "command",
      "note": "route join command"
    },
    {
      "from_node": "parent",
      "from_output": "message_data",
      "to_node": "JoinChannel",
      "to_input": "message_data",
      "note": "route join message data"
    },
    {
      "from_node": "ValidateAndExecuteSend",
      "from_output": "message_result",
      "to_node": "parent",
      "to_input": "message_result",
      "note": "return send result"
    },
    {
      "from_node": "RetrieveHistory",
      "from_output": "message_result",
      "to_node": "parent",
      "to_input": "message_result",
      "note": "return history result"
    },
    {
      "from_node": "CreateChannel",
      "from_output": "message_result",
      "to_node": "parent",
      "to_input": "message_result",
      "note": "return create_channel result"
    },
    {
      "from_node": "JoinChannel",
      "from_output": "message_result",
      "to_node": "parent",
      "to_input": "message_result",
      "note": "return join result"
    }
  ]
}
